import { logError } from '../utils/logger';

const BASE_URL = 'http://YOUR_LOCAL_IP:8000';

const guessMimeType = (name) => {
  const lower = (name || '').toLowerCase();
  if (lower.endsWith('.pdf')) return 'application/pdf';
  if (lower.endsWith('.mp3')) return 'audio/mpeg';
  if (lower.endsWith('.wav')) return 'audio/wav';
  if (lower.endsWith('.m4a')) return 'audio/x-m4a';
  if (lower.endsWith('.mp4')) return 'video/mp4';
  if (lower.endsWith('.mov')) return 'video/quicktime';
  if (lower.endsWith('.webm')) return 'video/webm';
  return 'application/octet-stream';
};

const makeFileData = (file, fieldName) => {
  const formData = new FormData();
  const name = file.name || `upload-${Date.now()}`;
  const type = file.mimeType || file.type || guessMimeType(name);

  formData.append(fieldName, {
    uri: file.uri,
    name,
    type,
  });

  return formData;
};

const handleApiError = (error) => {
  if (error?.response?.data?.detail) return error.response.data.detail;
  if (error?.message) return error.message;
  return 'Network Error';
};

/**
 * Audio to PDF Conversion
 */
export async function audioToPDF(file, filename, language = 'English') {
  const context = 'audioToPDF API';

  try {
    if (!file || !file.uri) {
      throw new Error('Invalid file object');
    }

    const data = makeFileData(file, 'file');
    data.append('filename', filename || 'voice2pdf');
    data.append('language', language);

    console.log(`🔄 Calling audioToPDF with file: ${file.name}, language: ${language}`);

    const response = await fetch(`${BASE_URL}/audio-to-pdf`, {
      method: 'POST',
      body: data,
    });

    if (!response.ok) {
      const errorText = await response.text();
      const error = new Error(
        `Server returned ${response.status}: ${errorText || 'Unknown error'}`
      );
      error.status = response.status;
      throw error;
    }

    const result = await response.json();
    console.log('✅ Audio to PDF conversion successful');
    return result;
  } catch (error) {
    const errorMsg = `Failed to convert audio to PDF: ${error.message}`;
    await logError(error, context);
    console.error('❌ ' + errorMsg);
    throw new Error(errorMsg);
  }
}

/**
 * PDF to Audio Conversion
 */
export async function pdfToAudio(file, language = 'English') {
  const context = 'pdfToAudio API';

  try {
    if (!file || !file.uri) {
      throw new Error('Invalid file object');
    }

    const data = makeFileData(file, 'file');
    data.append('language', language);

    console.log(`🔄 Calling pdfToAudio with file: ${file.name}, language: ${language}`);

    const response = await fetch(`${BASE_URL}/pdf-to-audio`, {
      method: 'POST',
      body: data,
    });

    if (!response.ok) {
      const errorText = await response.text();
      const error = new Error(
        `Server returned ${response.status}: ${errorText || 'Unknown error'}`
      );
      error.status = response.status;
      throw error;
    }

    const result = await response.json();
    console.log('✅ PDF to Audio conversion successful');
    return result;
  } catch (error) {
    const errorMsg = `Failed to convert PDF to audio: ${error.message}`;
    await logError(error, context);
    console.error('❌ ' + errorMsg);
    throw new Error(errorMsg);
  }
}

/**
 * PDF to All Audio Languages
 */
export async function pdfToAllAudio(file) {
  const context = 'pdfToAllAudio API';

  try {
    if (!file || !file.uri) {
      throw new Error('Invalid file object');
    }

    const data = makeFileData(file, 'file');

    console.log(`🔄 Calling pdfToAllAudio with file: ${file.name}`);

    const response = await fetch(`${BASE_URL}/pdf-to-all-audio`, {
      method: 'POST',
      body: data,
    });

    if (!response.ok) {
      const errorText = await response.text();
      const error = new Error(
        `Server returned ${response.status}: ${errorText || 'Unknown error'}`
      );
      error.status = response.status;
      throw error;
    }

    const result = await response.json();
    console.log('✅ PDF to All Audio conversion successful');
    return result;
  } catch (error) {
    const errorMsg = `Failed to convert PDF to all audio: ${error.message}`;
    await logError(error, context);
    console.error('❌ ' + errorMsg);
    throw new Error(errorMsg);
  }
}

/**
 * Realtime Transcription and Translation
 */
export async function realtimeAPI(file, language = 'English') {
  const context = 'Realtime API';

  try {
    if (!file || !file.uri) {
      throw new Error('Invalid file object');
    }

    const data = makeFileData(file, 'file');
    data.append('language', language);

    console.log(`🔄 Calling Realtime API with file: ${file.name}, language: ${language}`);

    const response = await fetch(`${BASE_URL}/realtime`, {
      method: 'POST',
      body: data,
    });

    if (!response.ok) {
      const errorText = await response.text();
      const error = new Error(
        `Server returned ${response.status}: ${errorText || 'Unknown error'}`
      );
      error.status = response.status;
      throw error;
    }

    const result = await response.json();
    console.log('✅ Realtime processing successful');
    return result;
  } catch (error) {
    const errorMsg = `Failed to process realtime request: ${error.message}`;
    await logError(error, context);
    console.error('❌ ' + errorMsg);
    throw new Error(errorMsg);
  }
}

/**
 * Health Check
 */
export async function healthCheck() {
  const context = 'Health Check';

  try {
    const response = await fetch(`${BASE_URL}/health`, {
      method: 'GET',
      timeout: 5000,
    });

    if (response.ok) {
      console.log('✅ Server is healthy');
      return true;
    }

    throw new Error(`Server health check failed: ${response.status}`);
  } catch (error) {
    await logError(error, context);
    console.error('❌ Server health check failed');
    return false;
  }
}

export { BASE_URL, handleApiError };
